import { GoogleEmbeddings, } from "@langchain/google-gauth";
/**
 * Integration with a chat model.
 */
export class GoogleVertexAIEmbeddings extends GoogleEmbeddings {
    static lc_name() {
        return "GoogleVertexAIEmbeddings";
    }
    constructor(fields) {
        super({
            ...fields,
            platformType: "gcp",
        });
    }
}
